parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
if (!body.retest_id || !body.result) return [{ json: { valid: false, error: 'retest_id and result required' } }];
if (!['pass','fail','partial'].includes(body.result)) return [{ json: { valid: false, error: 'result must be pass, fail, or partial' } }];
return [{ json: {
  valid: true,
  retest_id: body.retest_id,
  result: body.result,
  retest_evidence: body.retest_evidence || '',
  retested_by: body.retested_by || 'analyst',
  notes: body.notes || ''
} }];

